  (* D4: a=r, b=p, c=s, d=q.  Edges r→p, r→s, r→q, p→q, s→q. *)
  destruct (classic (R2 r p /\ R2 r s /\ R2 r q /\ R2 s q /\
                     forall x y : B, x <> y -> R2 x y ->
                       (x = r /\ y = p) \/ (x = r /\ y = s) \/
