       c <> d /\ c <> e /\
       d <> e /\
       R2 a b /\ R2 a c /\ R2 d a /\ R2 e d /\
       R2 d b /\ R2 d c /\ R2 e a /\ R2 e b /\ R2 e c /\
       (forall x y : B,
          R2 x y -> x = y \/
          ((x = a /\ y = b) \/ (x = a /\ y = c) \/ (x = d /\ y = a) \/
           (x = e /\ y = d) \/ (x = d /\ y = b) \/ (x = d /\ y = c) \/
           (x = e /\ y = a) \/ (x = e /\ y = b) \/ (x = e /\ y = c)))))
    as [HVcb | HnVcb].
  { apply (@n5_V_with_chain_below_apex_two_realizer B R2 HR2 Hcard).
    exact HVcb. }
  (* (eee) inv-V-shape with chain extending above the apex (9 edges). *)
  destruct (classic
    (exists a b c d e : B,
       a <> b /\ a <> c /\ a <> d /\ a <> e /\
       b <> c /\ b <> d /\ b <> e /\
       c <> d /\ c <> e /\
       d <> e /\
       R2 a c /\ R2 b c /\ R2 c d /\ R2 d e /\
       R2 a d /\ R2 b d /\ R2 a e /\ R2 b e /\ R2 c e /\
       (forall x y : B,
          R2 x y -> x = y \/
          ((x = a /\ y = c) \/ (x = b /\ y = c) \/ (x = c /\ y = d) \/
           (x = d /\ y = e) \/ (x = a /\ y = d) \/ (x = b /\ y = d) \/
           (x = a /\ y = e) \/ (x = b /\ y = e) \/ (x = c /\ y = e)))))
    as [HiVca | HniVca].
  { apply (@n5_inv_V_with_chain_above_apex_two_realizer B R2 HR2 Hcard).
    exact HiVca. }
  (* (fff) Two 3-chains sharing the middle element (8 edges). *)
  destruct (classic
    (exists a b c d e : B,
       a <> b /\ a <> c /\ a <> d /\ a <> e /\
       b <> c /\ b <> d /\ b <> e /\
       c <> d /\ c <> e /\
       d <> e /\
       R2 a b /\ R2 b c /\ R2 a c /\ R2 d b /\ R2 b e /\ R2 d e /\
       R2 a e /\ R2 d c /\
       (forall x y : B,
          R2 x y -> x = y \/
          ((x = a /\ y = b) \/ (x = b /\ y = c) \/ (x = a /\ y = c) \/
           (x = d /\ y = b) \/ (x = b /\ y = e) \/ (x = d /\ y = e) \/
           (x = a /\ y = e) \/ (x = d /\ y = c)))))
    as [HCSM | HnCSM].
  { apply (@n5_two_3chains_share_middle_two_realizer B R2 HR2 Hcard).
    exact HCSM. }
  (* (ggg) 3-claw-up with two leaves sharing a common top (6 edges). *)
  destruct (classic
    (exists a b c d e : B,
       a <> b /\ a <> c /\ a <> d /\ a <> e /\
       b <> c /\ b <> d /\ b <> e /\
       c <> d /\ c <> e /\
       d <> e /\
       R2 a b /\ R2 a c /\ R2 a d /\ R2 b e /\ R2 c e /\ R2 a e /\
       (forall x y : B,
          R2 x y -> x = y \/
          ((x = a /\ y = b) \/ (x = a /\ y = c) \/ (x = a /\ y = d) \/
           (x = b /\ y = e) \/ (x = c /\ y = e) \/ (x = a /\ y = e)))))
    as [HCLST | HnCLST].
  { apply (@n5_3claw_up_two_leaves_share_top_two_realizer B R2 HR2 Hcard).
    exact HCLST. }
  (* (hhh) 3-claw-down with two leaves sharing a common bottom (6 edges). *)
  destruct (classic
    (exists a b c d e : B,
       a <> b /\ a <> c /\ a <> d /\ a <> e /\
       b <> c /\ b <> d /\ b <> e /\
       c <> d /\ c <> e /\
       d <> e /\
       R2 a d /\ R2 b d /\ R2 c d /\ R2 e b /\ R2 e c /\ R2 e d /\
       (forall x y : B,
          R2 x y -> x = y \/
          ((x = a /\ y = d) \/ (x = b /\ y = d) \/ (x = c /\ y = d) \/
           (x = e /\ y = b) \/ (x = e /\ y = c) \/ (x = e /\ y = d)))))
    as [HCLSB | HnCLSB].
  { apply (@n5_3claw_down_two_leaves_share_bot_two_realizer B R2 HR2 Hcard).
    exact HCLSB. }
  (* (iii) 3-chain + top pendant with chain extending the pendant below
     (6 edges): a<b<c plus d<c plus e<d. *)
  destruct (classic
    (exists a b c d e : B,
       a <> b /\ a <> c /\ a <> d /\ a <> e /\
       b <> c /\ b <> d /\ b <> e /\
       c <> d /\ c <> e /\
       d <> e /\
       R2 a b /\ R2 b c /\ R2 a c /\ R2 d c /\ R2 e d /\ R2 e c /\
       (forall x y : B,
          R2 x y -> x = y \/
          ((x = a /\ y = b) \/ (x = b /\ y = c) \/ (x = a /\ y = c) \/
           (x = d /\ y = c) \/ (x = e /\ y = d) \/ (x = e /\ y = c)))))
    as [HTPCB | HnTPCB].
  { apply (@n5_chain3_top_pendant_with_chain_below_two_realizer B R2 HR2 Hcard).
    exact HTPCB. }
  (* (jjj) 3-chain + bot pendant with chain extending the pendant above
     (6 edges): a<b<c plus a<d plus d<e. *)
  destruct (classic
    (exists a b c d e : B,
       a <> b /\ a <> c /\ a <> d /\ a <> e /\
       b <> c /\ b <> d /\ b <> e /\
       c <> d /\ c <> e /\
       d <> e /\
       R2 a b /\ R2 b c /\ R2 a c /\ R2 a d /\ R2 d e /\ R2 a e /\
       (forall x y : B,
          R2 x y -> x = y \/
          ((x = a /\ y = b) \/ (x = b /\ y = c) \/ (x = a /\ y = c) \/
           (x = a /\ y = d) \/ (x = d /\ y = e) \/ (x = a /\ y = e)))))
    as [HBPCA | HnBPCA].
  { apply (@n5_chain3_bot_pendant_with_chain_above_two_realizer B R2 HR2 Hcard).
    exact HBPCA. }
  (* (kkk) Inverse T-shape extended: chain [c<b<a] + branch [d<b,d<a]
     + pendant [d<e] (6 edges). *)
  destruct (classic
    (exists a b c d e : B,
       a <> b /\ a <> c /\ a <> d /\ a <> e /\
       b <> c /\ b <> d /\ b <> e /\
       c <> d /\ c <> e /\
       d <> e /\
       R2 c b /\ R2 b a /\ R2 c a /\ R2 d b /\ R2 d a /\ R2 d e /\
       (forall x y : B,
          R2 x y -> x = y \/
          ((x = c /\ y = b) \/ (x = b /\ y = a) \/ (x = c /\ y = a) \/
           (x = d /\ y = b) \/ (x = d /\ y = a) \/ (x = d /\ y = e)))))
    as [HInvT | HnInvT].
  { apply (@n5_inv_T_shape_extended_two_realizer B R2 HR2 Hcard).
    exact HInvT. }
  (* (lll) Chain [a<b] with a 3-claw at the top: b<c, b<d, b<e
     (7 edges). *)
  destruct (classic
    (exists a b c d e : B,
       a <> b /\ a <> c /\ a <> d /\ a <> e /\
       b <> c /\ b <> d /\ b <> e /\
       c <> d /\ c <> e /\
       d <> e /\
       R2 a b /\ R2 b c /\ R2 b d /\ R2 b e /\
       R2 a c /\ R2 a d /\ R2 a e /\
       (forall x y : B,
          R2 x y -> x = y \/
          ((x = a /\ y = b) \/ (x = b /\ y = c) \/ (x = b /\ y = d) \/
           (x = b /\ y = e) \/
           (x = a /\ y = c) \/ (x = a /\ y = d) \/ (x = a /\ y = e)))))
    as [HC23CT | HnC23CT].
  { apply (@n5_chain2_plus_3claw_top_two_realizer B R2 HR2 Hcard).
    exact HC23CT. }
  (* (mmm) 3-claw at the bottom with a 2-chain on top: c<a, d<a, e<a,
     and a<b (7 edges). *)
  destruct (classic
    (exists a b c d e : B,
       a <> b /\ a <> c /\ a <> d /\ a <> e /\
       b <> c /\ b <> d /\ b <> e /\
       c <> d /\ c <> e /\
       d <> e /\
       R2 c a /\ R2 d a /\ R2 e a /\ R2 a b /\
       R2 c b /\ R2 d b /\ R2 e b /\
       (forall x y : B,
          R2 x y -> x = y \/
          ((x = c /\ y = a) \/ (x = d /\ y = a) \/ (x = e /\ y = a) \/
           (x = a /\ y = b) \/
           (x = c /\ y = b) \/ (x = d /\ y = b) \/ (x = e /\ y = b)))))
    as [HC23CB | HnC23CB].
  { apply (@n5_chain2_plus_3claw_bot_two_realizer B R2 HR2 Hcard).
    exact HC23CB. }
  (* (nnn) 3-claw-up with chain extending below the apex: a<b, a<c, a<d,
     e<a, plus transitively e<b, e<c, e<d (7 edges). *)
  destruct (classic
    (exists a b c d e : B,
       a <> b /\ a <> c /\ a <> d /\ a <> e /\
       b <> c /\ b <> d /\ b <> e /\
       c <> d /\ c <> e /\
       d <> e /\
       R2 a b /\ R2 a c /\ R2 a d /\ R2 e a /\
       R2 e b /\ R2 e c /\ R2 e d /\
       (forall x y : B,
          R2 x y -> x = y \/
          ((x = a /\ y = b) \/ (x = a /\ y = c) \/ (x = a /\ y = d) \/
           (x = e /\ y = a) \/
           (x = e /\ y = b) \/ (x = e /\ y = c) \/ (x = e /\ y = d)))))
    as [HCUCB | HnCUCB].
  { apply (@n5_3claw_up_chain_below_apex_two_realizer B R2 HR2 Hcard).
    exact HCUCB. }
  (* (ooo) 3-claw-down with chain extending above the apex: b<a, c<a, d<a,
     a<e, plus transitively b<e, c<e, d<e (7 edges). *)
  destruct (classic
    (exists a b c d e : B,
       a <> b /\ a <> c /\ a <> d /\ a <> e /\
       b <> c /\ b <> d /\ b <> e /\
       c <> d /\ c <> e /\
       d <> e /\
       R2 b a /\ R2 c a /\ R2 d a /\ R2 a e /\
       R2 b e /\ R2 c e /\ R2 d e /\
       (forall x y : B,
          R2 x y -> x = y \/
          ((x = b /\ y = a) \/ (x = c /\ y = a) \/ (x = d /\ y = a) \/
           (x = a /\ y = e) \/
           (x = b /\ y = e) \/ (x = c /\ y = e) \/ (x = d /\ y = e)))))
    as [HCDCA | HnCDCA].
  { apply (@n5_3claw_down_chain_above_apex_two_realizer B R2 HR2 Hcard).
    exact HCDCA. }
  (* (ppp) N-shape with bottom extension: a<b, c<b, c<d, e<a (plus
     transitively e<b) (5 edges). *)
  destruct (classic
    (exists a b c d e : B,
       a <> b /\ a <> c /\ a <> d /\ a <> e /\
       b <> c /\ b <> d /\ b <> e /\
       c <> d /\ c <> e /\
       d <> e /\
       R2 a b /\ R2 c b /\ R2 c d /\ R2 e a /\ R2 e b /\
       (forall x y : B,
          R2 x y -> x = y \/
          ((x = a /\ y = b) \/ (x = c /\ y = b) \/ (x = c /\ y = d) \/
           (x = e /\ y = a) \/ (x = e /\ y = b)))))
    as [HNBE | HnNBE].
  { apply (@n5_N_plus_bottom_extension_two_realizer B R2 HR2 Hcard).
    exact HNBE. }
  (* (qqq) N-shape + top pendant on left chain: a<b, c<b, c<d, a<e
     (4 edges, e above a only). *)
  destruct (classic
    (exists a b c d e : B,
       a <> b /\ a <> c /\ a <> d /\ a <> e /\
       b <> c /\ b <> d /\ b <> e /\
       c <> d /\ c <> e /\
       d <> e /\
       R2 a b /\ R2 c b /\ R2 c d /\ R2 a e /\
       (forall x y : B,
          R2 x y -> x = y \/
          ((x = a /\ y = b) \/ (x = c /\ y = b) \/ (x = c /\ y = d) \/
           (x = a /\ y = e)))))
    as [HNTPL | HnNTPL].
  { apply (@n5_N_plus_top_pendant_on_left_two_realizer B R2 HR2 Hcard).
    exact HNTPL. }
  (* (rrr) 3-claw-up at apex [c] with extra pendant at one leaf: c<b,
     c<d, c<e, a<b (4 edges, a below leaf b only). *)
  destruct (classic
    (exists a b c d e : B,
       a <> b /\ a <> c /\ a <> d /\ a <> e /\
       b <> c /\ b <> d /\ b <> e /\
       c <> d /\ c <> e /\
       d <> e /\
       R2 a b /\ R2 c b /\ R2 c d /\ R2 c e /\
       (forall x y : B,
          R2 x y -> x = y \/
          ((x = a /\ y = b) \/ (x = c /\ y = b) \/ (x = c /\ y = d) \/
           (x = c /\ y = e)))))
    as [HClawL | HnClawL].
  { apply (@n5_3claw_up_pendant_at_one_leaf_two_realizer B R2 HR2 Hcard).
    exact HClawL. }
  (* (ll-d) Y-down with pendant above the top (9 edges).  Dual of (ll). *)
  destruct (classic
    (exists a b c d e : B,
       a <> b /\ a <> c /\ a <> d /\ a <> e /\
       b <> c /\ b <> d /\ b <> e /\
       c <> d /\ c <> e /\
       d <> e /\
       R2 c b /\ R2 d b /\ R2 b a /\ R2 c a /\ R2 d a /\
       R2 a e /\ R2 b e /\ R2 c e /\ R2 d e /\
       (forall x y : B,
          R2 x y -> x = y \/
          ((x = c /\ y = b) \/ (x = d /\ y = b) \/ (x = b /\ y = a) \/
           (x = c /\ y = a) \/ (x = d /\ y = a) \/
           (x = a /\ y = e) \/ (x = b /\ y = e) \/ (x = c /\ y = e) \/
           (x = d /\ y = e)))))
    as [HYdpa | HnYdpa].
  { destruct HYdpa as [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRcb [HRdb [HRba [HRca [HRda
       [HRae [HRbe [HRce [HRde HR_only]]]]]]]]]]]]]]]]]]]]]]]].
    apply (@n5_Y_down_pendant_above_two_realizer B R2 HR2 Hcard).
    exists a, b, c, d, e.
    repeat split; assumption. }
  (* (ppp-d) inv-N + top-extension on one chain: b<a, b<c, d<c, a<e
     (plus transitively b<e) (5 edges).  Dual of (ppp). *)
  destruct (classic
    (exists a b c d e : B,
       a <> b /\ a <> c /\ a <> d /\ a <> e /\
       b <> c /\ b <> d /\ b <> e /\
       c <> d /\ c <> e /\
       d <> e /\
       R2 b a /\ R2 b c /\ R2 d c /\ R2 a e /\ R2 b e /\
       (forall x y : B,
          R2 x y -> x = y \/
          ((x = b /\ y = a) \/ (x = b /\ y = c) \/ (x = d /\ y = c) \/
           (x = a /\ y = e) \/ (x = b /\ y = e)))))
    as [HInvNTE | HnInvNTE].
  { apply (@n5_inv_N_plus_top_extension_two_realizer B R2 HR2 Hcard).
    exact HInvNTE. }
  (* (rrr-d) 3-claw-down at apex [c] with extra pendant at one leaf:
     b<c, d<c, e<c, b<a (4 edges, a above leaf b only).  Dual of (rrr). *)
  destruct (classic
    (exists a b c d e : B,
       a <> b /\ a <> c /\ a <> d /\ a <> e /\
       b <> c /\ b <> d /\ b <> e /\
       c <> d /\ c <> e /\
       d <> e /\
       R2 b a /\ R2 b c /\ R2 d c /\ R2 e c /\
       (forall x y : B,
          R2 x y -> x = y \/
          ((x = b /\ y = a) \/ (x = b /\ y = c) \/ (x = d /\ y = c) \/
           (x = e /\ y = c)))))
    as [HClawLD | HnClawLD].
  { apply (@n5_3claw_down_pendant_at_one_leaf_two_realizer B R2 HR2 Hcard).
    exact HClawLD. }
  (* (sss) inv-N + bot-pendant on left chain: b<a, b<c, d<c, e<a
     (4 edges, e below a only).  Dual of (qqq). *)
  destruct (classic
    (exists a b c d e : B,
       a <> b /\ a <> c /\ a <> d /\ a <> e /\
       b <> c /\ b <> d /\ b <> e /\
       c <> d /\ c <> e /\
       d <> e /\
       R2 b a /\ R2 b c /\ R2 d c /\ R2 e a /\
       (forall x y : B,
          R2 x y -> x = y \/
          ((x = b /\ y = a) \/ (x = b /\ y = c) \/ (x = d /\ y = c) \/
           (x = e /\ y = a)))))
    as [HInvNBPL | HnInvNBPL].
  { apply (@n5_inv_N_plus_bot_pendant_on_left_two_realizer B R2 HR2 Hcard).
    exact HInvNBPL. }
  (* Fall-through: either one_edge or residual. *)
  destruct (classic (exists x y : B, x <> y /\ R2 x y /\ ~ (x = p /\ y = q)))
    as [Hother | Honly].
  - (* Some other strict edge exists: route to the residual admit. *)
    destruct Hother as [x [y [Hxy_neq [HRxy Hnot_pq]]]].
    apply (@n5_residual_classes_two_realizer B R2 HR2 Hcard
             Hnonantichain Hinc_ex).
    exists p, q, x, y.
    split; [exact Hpq_neq |].
    split; [exact HRpq |].
    split; [exact Hxy_neq |].
    split; [exact HRxy |].
    exact Hnot_pq.
  - (* Only (p, q) is a non-trivial relation: class (a). *)
    apply (@n5_one_edge_two_realizer B R2 HR2 Hcard).
    exists p, q.
    split; [exact Hpq_neq |].
    split; [exact HRpq |].
    intros a b HRab.
    destruct (classic (a = b)) as [Heq | Hneq]; [left; exact Heq |].
    right.
    destruct (classic (a = p /\ b = q)) as [Hpq_match | Hnot_pq].
    + exact Hpq_match.
    + exfalso. apply Honly.
      exists a, b. split; [exact Hneq |]. split; [exact HRab |]. exact Hnot_pq.
Qed.

(** Outer lemma: 2-realizer for n ∈ {4, 5} non-antichain non-chain.

    Composed [Qed] from two size-specific helpers:
      - [n4_nonantichain_nonchain_two_realizer]  (n = 4)
      - [n5_nonantichain_nonchain_two_realizer]  (n = 5)

    The n=4 dispatcher itself is wired (uniformly, for now, through
    [n4_residual_classes_two_realizer]) to the family of six Qed
    sub-lemmas closing the (a)-(f) isomorphism classes:
    [n4_one_edge_two_realizer],
    [n4_chain_plus_isolated_two_realizer],
    [n4_V_two_realizer], [n4_inv_V_two_realizer],
    [n4_disjoint_chains_two_realizer], [n4_N_two_realizer]. *)
Lemma nonantichain_nonchain_small_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2} (n : nat),
  cardinal B (Full_set B) n ->
  (n = 4 \/ n = 5) ->
  ~ (forall a b : B, R2 a b -> a = b) ->
  (exists a b : B, @Incomparable B R2 a b) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 n Hcard Hn45 Hnonantichain Hinc_ex.
  destruct Hn45 as [Hn4 | Hn5].
  - (* n = 4: route to the n=4 dispatcher (which routes the 6 named
       classes (a)-(f) to their Qed sub-lemmas, with the residual 8
       classes captured by [n4_residual_classes_two_realizer]). *)
    subst n.
    exact (@n4_nonantichain_nonchain_two_realizer B R2 HR2 Hcard
             Hnonantichain Hinc_ex).
  - (* n = 5: route to the focused n=5 admit. *)
    subst n.
    exact (@n5_nonantichain_nonchain_two_realizer B R2 HR2 Hcard
             Hnonantichain Hinc_ex).
Qed.

(** Hiraguchi's bound for the small base cases n in {4, 5}.

    For these sizes the inductive step in [hiraguchi_helper] would
    recurse to subposets of size <= 3, which is below Hiraguchi's
    threshold.  The classical Hiraguchi proof handles these via a
    direct small-finite analysis (or via a different decomposition for
    the antichain).

    The proof here case-splits on whether [R2] has any incomparable
    pair, and then on whether [R2] is an antichain:

    - **Chain case** (no incomparable pair): [R2] is a total order so
      the singleton [Singleton _ R2] is a 1-element realizer.  This
      gives [d2 <= 1 <= 2].  Closed cleanly.

    - **Antichain non-chain case** (R2 = eq, some pair incomparable):
      closed via [antichain_two_realizer] — opposite total orders form
      a 2-element realizer of any antichain with ≥ 2 distinct elements.
      Note this is the tightness witness for Hiraguchi at n = 4
      (the 4-antichain has dim = 2 = 4/2).

    - **Non-antichain non-chain case**: routed through the focused
      Admitted helper [nonantichain_nonchain_small_two_realizer] which
      produces a 2-realizer directly.  [dimension_is_minimum] then
      gives d2 <= 2.

    With the focused helper in place, this lemma is [Qed]; the only
    remaining gap is the helper's body. *)
Lemma hiraguchi_small_case :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2}
         (n d2 : nat),
  cardinal B (Full_set B) n ->
  (n = 4 \/ n = 5) ->
  PosetDimension R2 d2 ->
  d2 <= 2.
Proof.
  intros B R2 HR2 n d2 Hcard Hn45 Hdim.
  destruct (classic (exists a b, @Incomparable B R2 a b)) as [Hinc_ex | Hchain].
  - (* Non-chain case.  Split on whether R2 is an antichain. *)
    destruct (classic (forall a b : B, R2 a b -> a = b)) as [HR2_antichain | HR2_nonantichain].
    + (* Antichain case: construct a 2-realizer directly via
         [antichain_two_realizer], using opposite total orders.

         The incomparable pair (a, b) provides two distinct elements
         needed for the 2-realizer to have cardinality exactly 2. *)
      destruct Hinc_ex as [a [b Hinc_ab]].
      assert (Hab_neq : a <> b).
      { intro Heq. apply Hinc_ab. left. rewrite Heq. apply HR2.(poset_refl). }
      destruct (@antichain_two_realizer B R2 HR2 HR2_antichain
                  (ex_intro _ a (ex_intro _ b Hab_neq)))
        as [r [Hr_real Hr_card]].
      exact (dimension_is_minimum (R := R2) (d := d2) Hdim r 2 Hr_real Hr_card).
    + (* Non-antichain non-chain case: use focused Admitted helper. *)
      destruct (@nonantichain_nonchain_small_two_realizer B R2 HR2 n
                  Hcard Hn45 HR2_nonantichain Hinc_ex)
        as [r [Hr_real Hr_card]].
      exact (dimension_is_minimum (R := R2) (d := d2) Hdim r 2 Hr_real Hr_card).
  - (* Chain case: R2 is a total order, dim R2 <= 1 <= 2.
       Construction mirrors the chain branch of [hiraguchi_helper]. *)
    assert (Hd1 : d2 <= 1).
    { assert (HR2_total : @IsTotalOrder B R2).
      { constructor; [exact HR2 |].
        intros a b.
        destruct (classic (R2 a b)) as [Hab | Hnab]; [left; assumption |].
        right.
        destruct (classic (R2 b a)) as [Hba | Hnba]; [assumption |].
        exfalso. apply Hchain. exists a, b.
        unfold Incomparable. intros [H1 | H2]; contradiction. }
      set (rSingle := Singleton (B -> B -> Prop) R2).
      assert (HrS_card : cardinal (B -> B -> Prop) rSingle 1)
        by exact (singleton_cardinal _ R2).
      assert (HrS_real : @IsRealizer B R2 rSingle).
      { constructor.
        - intros L HL. destruct HL.
          constructor; [exact HR2_total | intros a b Hab; exact Hab].
        - intros a b. split.
          + intros HRab L HL. destruct HL. exact HRab.
          + intro Hall. apply Hall. constructor. }
      exact (dimension_is_minimum (R := R2) (d := d2) Hdim rSingle 1
               HrS_real HrS_card). }
    lia.
Qed.

(** * Hiraguchi's Theorem via removable pairs.

    Strong induction on n.  For n >= 6 the induction step uses
    [removable_pair_exists] to obtain a removable pair (x, y) (when an
    incomparable pair exists), then bounds the dimension of the
    residual subposet by IH (since |Residual| = n - 2 >= 4) and lifts
    via [removable_pair_dimension_bound].  The chain case (no
    incomparable pair) gives dim <= 1.

    For n in {4, 5} we appeal to the separate [hiraguchi_small_case]
    axiom (a genuine small-finite gap, kept Admitted with a precise
    statement). *)
Lemma hiraguchi_helper :
  forall (n : nat) {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2} (d2 : nat),
  cardinal B (Full_set B) n ->
  n >= 4 ->
  PosetDimension R2 d2 ->
  d2 <= n / 2.
Proof.
  intro n.
  induction n as [n IH] using lt_wf_ind.
  intros B R2 HR2 d2 Hcard Hn4 Hdim.
  (* Split on n in {4, 5} vs n >= 6 *)
  destruct (Nat.lt_ge_cases n 6) as [Hlt6 | Hge6].
  { (* Base case: n in {4, 5}, dim <= 2 <= n / 2 *)
    assert (Hn45 : n = 4 \/ n = 5) by lia.
    assert (Hd2 : d2 <= 2)
      by exact (@hiraguchi_small_case B R2 HR2 n d2 Hcard Hn45 Hdim).
    destruct Hn45 as [-> | ->]; simpl; lia. }
  (* n >= 6: case-split on chain / non-chain *)
  destruct (classic (exists a b, @Incomparable B R2 a b)) as [Hinc_ex | Hchain].
  - (* Non-chain: removable pair exists, recurse on (n - 2)-residual *)
    destruct (@removable_pair_exists B R2 HR2 n Hcard Hn4 Hinc_ex)
      as [x [y Hrem]].
    pose proof Hrem as Hrem_full.
    destruct Hrem as [Hxy_neq Hrem_prop].
    (* Compute the cardinal of Residual x y, which is n - 2 *)
    assert (Hn2 : n >= 2) by lia.
    assert (Hx_in : In B (Full_set B) x) by apply Full_intro.
    assert (Hcard_minus1 : cardinal B (Subtract B (Full_set B) x) (pred n)).
    { assert (Hn_pos : 0 < n) by lia.
      rewrite <- (Nat.succ_pred_pos n Hn_pos) in Hcard.
      exact (cardinal_subtract_sn B (Full_set B) x (pred n) Hcard Hx_in). }
    assert (Hy_in1 : In B (Subtract B (Full_set B) x) y).
    { split; [apply Full_intro |].
      intro Hin. inversion Hin as [Hxy_eq]. apply Hxy_neq. exact Hxy_eq. }
    assert (Hcard_minus2 : cardinal B (@Residual B x y) (pred (pred n))).
    { assert (Hpredn_pos : 0 < pred n) by lia.
      rewrite <- (Nat.succ_pred_pos (pred n) Hpredn_pos) in Hcard_minus1.
      unfold Residual.
      (* Convert Subtract to Setminus form *)
      replace (Subtract B (Full_set B) x) with
              (Setminus B (Full_set B) (Singleton B x)) in Hcard_minus1
        by reflexivity.
      exact (cardinal_subtract_sn B _ y (pred (pred n)) Hcard_minus1 Hy_in1). }
    (* Apply subposet_dimension_le on Residual to get a sub-dimension d_q <= d2 *)
    destruct (subposet_dimension_le R2 (@Residual B x y) d2 Hdim)
      as [d_q [HdimQ_inh' Hd_q_le]].
    destruct HdimQ_inh' as [HdimQ].
    (* IH gives d_q <= (n - 2) / 2 *)
    assert (Hd_q_bound : d_q <= pred (pred n) / 2).
    { assert (Hcard_sub :
        cardinal {a : B | In B (@Residual B x y) a}
                 (Full_set {a : B | In B (@Residual B x y) a})
                 (pred (pred n))).
      { exact (cardinal_subtype_full B (@Residual B x y) (pred (pred n))
                 Hcard_minus2). }
      assert (Hpp_ge4 : pred (pred n) >= 4) by lia.
      exact (IH (pred (pred n)) ltac:(lia)
                {a : B | In B (@Residual B x y) a}
                (fun a b => R2 (proj1_sig a) (proj1_sig b))
                (subtype_is_poset R2 (@Residual B x y))
                d_q
                Hcard_sub Hpp_ge4 HdimQ). }
    (* Use removable_pair_dimension_bound to lift d_q to a (d_q + 1)-realizer of R2 *)
    assert (Hd_ext : d2 <= d_q + 1).
    { pose proof (dimension_is_realizer HdimQ) as HrSub_real.
      pose proof (dimension_cardinality HdimQ) as HrSub_card.
      destruct (@removable_pair_dimension_bound B R2 x y d_q
                  (dimension_realizer HdimQ)
                  Hrem_full HrSub_real HrSub_card)
        as [r [Hr_real Hr_card]].
      exact (dimension_is_minimum (R := R2) (d := d2) Hdim r (d_q + 1)
               Hr_real Hr_card). }
    (* Arithmetic: d_q + 1 <= (n - 2) / 2 + 1 = n / 2 for n >= 6 *)
    assert (Hbridge : pred (pred n) / 2 + 1 <= n / 2).
    { replace (pred (pred n)) with (n - 2) by lia.
      assert (Heq : n / 2 = (n - 2) / 2 + 1).
      { replace n with ((n - 2) + 1 * 2) at 1 by lia.
        rewrite Nat.div_add by lia. lia. }
      lia. }
    lia.
  - (* Chain: R2 is a total order, dim R2 <= 1 *)
    assert (Hd1 : d2 <= 1).
    { assert (HR2_total : @IsTotalOrder B R2).
      { constructor; [exact HR2 |].
        intros a b.
        destruct (classic (R2 a b)) as [Hab | Hnab]; [left; assumption |].
        right.
        destruct (classic (R2 b a)) as [Hba | Hnba]; [assumption |].
        exfalso. apply Hchain. exists a, b.
        unfold Incomparable. intros [H1 | H2]; contradiction. }
      set (rSingle := Singleton (B -> B -> Prop) R2).
      assert (HrS_card : cardinal (B -> B -> Prop) rSingle 1)
        by exact (singleton_cardinal _ R2).
      assert (HrS_real : @IsRealizer B R2 rSingle).
      { constructor.
        - intros L HL. destruct HL.
          constructor; [exact HR2_total | intros a b Hab; exact Hab].
        - intros a b. split.
          + intros HRab L HL. destruct HL. exact HRab.
          + intro Hall. apply Hall. constructor. }
      exact (dimension_is_minimum (R := R2) (d := d2) Hdim rSingle 1
               HrS_real HrS_card). }
    assert (Hnhalf : 1 <= n / 2) by (apply Nat.div_le_lower_bound; lia).
    lia.
Qed.

(** Hiraguchi's Theorem (1951), carrier-polymorphic form.
    Re-exports [hiraguchi_helper] under its historical name. *)
Lemma hiraguchi_thm :
  forall (n : nat) {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2} (d2 : nat),
  cardinal B (Full_set B) n ->
  n >= 4 ->
  PosetDimension R2 d2 ->
  d2 <= n / 2.
Proof.
  intros n B R2 HR2 d2 Hcard Hn4 Hdim.
  exact (@hiraguchi_helper n B R2 HR2 d2 Hcard Hn4 Hdim).
Qed.

(** Hiraguchi's Theorem, specialised form: section-arg corollary. *)
Theorem hiraguchi_bound :
  forall {A : Type} (R : A -> A -> Prop) `{IsPoset A R} (n d : nat),
  cardinal A (Full_set A) n ->
  n >= 4 ->
  PosetDimension R d ->
  d <= n / 2.
Proof.
  intros A R HR n d Hcard Hn4 Hdim.
  exact (@hiraguchi_helper n A R HR d Hcard Hn4 Hdim).
Qed.



